/// MolmoAct2 vision adapter: 2×2 attention-pooling + SwiGLU projector.
///
/// Mirrors the REAL MolmoAct2 `image_pooling_2d` (a
/// `ViTMultiHeadDotProductAttention`) followed by `image_projector`
/// (an `ImageProjectorMLP`), exactly as in modeling_molmoact2.py
/// (`MolmoAct2VisionBackbone.forward`, ~lines 1866-1928).
///
/// ── Grouping (the load-bearing detail) ──────────────────────────────────
/// The ViT emits 729 patch features on a 27×27 grid; each patch feature is the
/// concatenation of the 2 extracted ViT layers → 2304-d (= vit_hidden 1152 × 2).
/// The image processor's `arange_for_pooling` (image_processing_molmoact2.py)
/// does 2×2 SPATIAL pooling: it pads the 27×27 grid to 28×28 with -1 (pad split
/// = [top=0,bottom=1] and [left=0,right=1] for the +1 pad), then
/// `einops.rearrange("(h dh) (w dw) -> h w (dh dw)", dh=2, dw=2)` groups it into
/// a 14×14 grid of 4-patch groups → **196 pooled tokens, 4 patches each**.
/// Padded slots (index -1) contribute a ZERO feature vector to both the group
/// mean and the attention (this checkpoint's `pooling_attention_mask` is False,
/// so the query is a plain `mean(-2)` over all 4 group members and attention is
/// over all 4, with the masked-out members already zeroed).
///
/// ── Per-group computation ───────────────────────────────────────────────
///   1. query = mean over the group's 4 patch features (2304-d).
///   2. xq = wq·query + bq, xk = wk·feat + bk, xv = wv·feat + bv   (2304→1152),
///      reshape to 16 heads × 72.
///   3. attention: the single query attends over the group's 4 patches (k/v),
///      16 heads, scale 1/√72, softmax, weighted sum.
///   4. out = wo·attn + bo   (1152→1152).
///   5. projector SwiGLU: down( silu(gate(out)) * up(out) )  → 2560 (text hidden).
/// Output: `[num_output_tokens=196, text_hidden=2560]`.
///
/// Knot tensor names (emitted by encode-molmo.py):
///   adapter_attn_q_weight  [1152, 2304]  adapter_attn_q_bias  [1152]   (wq)
///   adapter_attn_k_weight  [1152, 2304]  adapter_attn_k_bias  [1152]   (wk)
///   adapter_attn_v_weight  [1152, 2304]  adapter_attn_v_bias  [1152]   (wv)
///   adapter_attn_out_weight[1152, 1152]  adapter_attn_out_bias[1152]   (wo)
///   adapter_proj_gate_weight [9728, 1152]   (w1, gate)
///   adapter_proj_up_weight   [9728, 1152]   (w3, up)
///   adapter_proj_down_weight [2560, 9728]   (w2, down)
/// There is NO adapter_query_weight and NO adapter_kv_ln_* (the query is a mean,
/// and there is no pre-KV layer norm).
use std::sync::Arc;

use crate::loader::{OwnedBytes, WeightBackend};
use crate::math::{accumulate_weighted, dot_product, mat_vec_f32, softmax};
use crate::model_molmoact2_config::MolmoAct2AdapterConfig;

/// Patches in each 2×2 pooling group.
const POOL_H: usize = 2;
const POOL_W: usize = 2;
const GROUP_SIZE: usize = POOL_H * POOL_W; // 4

pub struct MolmoAct2Adapter {
    pub config: MolmoAct2AdapterConfig,
    backend: Arc<dyn WeightBackend>,
}

impl MolmoAct2Adapter {
    pub fn new(config: MolmoAct2AdapterConfig, backend: Arc<dyn WeightBackend>) -> Self {
        Self { config, backend }
    }

    /// Map ViT output `[n_patches, input_dim]` → LM-ready features
    /// `[num_output_tokens, text_hidden_size]`.
    ///
    /// `vit_out`: row-major `[n_patches, input_dim=2304]`, where each row is the
    /// concatenation of the 2 extracted ViT layers for one patch. `n_patches` is
    /// 729 (27×27) for the single 378×378 crop the runtime currently handles.
    pub fn forward(&mut self, vit_out: &[f32], n_patches: usize) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size; // 1152
        let in_dim = cfg.input_dim; // 2304
        let n_heads = cfg.num_attention_heads; // 16
        let head_dim = cfg.head_dim(); // 72
        let scale = 1.0 / (head_dim as f32).sqrt();
        let inter = cfg.intermediate_size; // 9728
        let text_h = cfg.text_hidden_size; // 2560

        if vit_out.len() < n_patches * in_dim {
            return Err(format!(
                "vit_out too small: have {} floats, need {} ({} patches × {} dim)",
                vit_out.len(),
                n_patches * in_dim,
                n_patches,
                in_dim
            ));
        }

        // ── Recover the 27×27 patch grid and build the 2×2 pooling groups ────
        let grid = isqrt(n_patches);
        if grid * grid != n_patches {
            return Err(format!(
                "n_patches {} is not a perfect square; cannot form a patch grid",
                n_patches
            ));
        }
        // Padded grid dims (pad up to a multiple of the pool factor).
        let gh = grid.div_ceil(POOL_H); // 14
        let gw = grid.div_ceil(POOL_W); // 14
        let padded_h = gh * POOL_H; // 28
        let padded_w = gw * POOL_W; // 28
                                    // Asymmetric pad split (mirrors np.pad [h_pad//2, (h_pad+1)//2]):
                                    // extra row/col land at the BOTTOM / RIGHT.
        let pad_top = (padded_h - grid) / 2;
        let pad_left = (padded_w - grid) / 2;
        let n_groups = gh * gw; // 196

        // For each group, flatten the GROUP_SIZE member patch indices into the
        // padded grid, then map back to the real 27×27 flat index (-1 if padded).
        // einops "(h dh) (w dw) -> h w (dh dw)" member order: (dh, dw) row-major.
        let mut group_members: Vec<[isize; GROUP_SIZE]> = Vec::with_capacity(n_groups);
        for ph in 0..gh {
            for pw in 0..gw {
                let mut members = [-1isize; GROUP_SIZE];
                let mut m = 0;
                for dh in 0..POOL_H {
                    for dw in 0..POOL_W {
                        let padded_row = ph * POOL_H + dh;
                        let padded_col = pw * POOL_W + dw;
                        // Translate padded coords → real grid coords.
                        let real = if padded_row >= pad_top
                            && padded_col >= pad_left
                            && padded_row < pad_top + grid
                            && padded_col < pad_left + grid
                        {
                            let r = padded_row - pad_top;
                            let c = padded_col - pad_left;
                            (r * grid + c) as isize
                        } else {
                            -1
                        };
                        members[m] = real;
                        m += 1;
                    }
                }
                group_members.push(members);
            }
        }

        // ── Fetch projection weights once (keep the byte handles alive) ──────
        let q_w_b = self.fetch("adapter_attn_q_weight")?;
        let q_b_b = self.fetch("adapter_attn_q_bias")?;
        let k_w_b = self.fetch("adapter_attn_k_weight")?;
        let k_b_b = self.fetch("adapter_attn_k_bias")?;
        let v_w_b = self.fetch("adapter_attn_v_weight")?;
        let v_b_b = self.fetch("adapter_attn_v_bias")?;
        let o_w_b = self.fetch("adapter_attn_out_weight")?;
        let o_b_b = self.fetch("adapter_attn_out_bias")?;
        let gate_w_b = self.fetch("adapter_proj_gate_weight")?;
        let up_w_b = self.fetch("adapter_proj_up_weight")?;
        let down_w_b = self.fetch("adapter_proj_down_weight")?;

        let q_w = bytes_to_f32(&q_w_b);
        let q_b = bytes_to_f32(&q_b_b);
        let k_w = bytes_to_f32(&k_w_b);
        let k_b = bytes_to_f32(&k_b_b);
        let v_w = bytes_to_f32(&v_w_b);
        let v_b = bytes_to_f32(&v_b_b);
        let o_w = bytes_to_f32(&o_w_b);
        let o_b = bytes_to_f32(&o_b_b);
        let gate_w = bytes_to_f32(&gate_w_b);
        let up_w = bytes_to_f32(&up_w_b);
        let down_w = bytes_to_f32(&down_w_b);

        // ── Scratch buffers (per-group) ──────────────────────────────────────
        let mut query = vec![0.0f32; in_dim]; // group mean (2304-d)
        let mut xq = vec![0.0f32; h]; // 16×72 = 1152
        let mut xk = vec![0.0f32; GROUP_SIZE * h]; // K for the ≤4 group patches
        let mut xv = vec![0.0f32; GROUP_SIZE * h];
        let mut attn_out = vec![0.0f32; h]; // merged-heads attn output
        let mut proj_in = vec![0.0f32; h]; // wo output (1152)
        let mut gate = vec![0.0f32; inter];
        let mut up = vec![0.0f32; inter];
        let mut mid = vec![0.0f32; inter];
        let mut scores = vec![0.0f32; GROUP_SIZE];

        let mut out = vec![0.0f32; n_groups * text_h];

        for (gi, members) in group_members.iter().enumerate() {
            // 1. query = mean over the group's 4 patch features (padded → zeros).
            //    Padded members contribute a zero vector; the mean still divides
            //    by GROUP_SIZE (modeling.py uses to_pool.mean(-2) over all 4,
            //    because pooling_attention_mask is False for this checkpoint).
            for q in query.iter_mut() {
                *q = 0.0;
            }
            for &idx in members.iter() {
                if idx >= 0 {
                    let row = &vit_out[idx as usize * in_dim..(idx as usize + 1) * in_dim];
                    for (acc, &f) in query.iter_mut().zip(row.iter()) {
                        *acc += f;
                    }
                }
            }
            let inv = 1.0 / GROUP_SIZE as f32;
            for q in query.iter_mut() {
                *q *= inv;
            }

            // 2. Project Q from the group query, K/V from each group patch.
            mat_vec_f32(&mut xq, &query, q_w, h, in_dim);
            for i in 0..h {
                xq[i] += q_b[i];
            }
            for (m, &idx) in members.iter().enumerate() {
                let xk_row = &mut xk[m * h..(m + 1) * h];
                let xv_row = &mut xv[m * h..(m + 1) * h];
                if idx >= 0 {
                    let feat = &vit_out[idx as usize * in_dim..(idx as usize + 1) * in_dim];
                    mat_vec_f32(xk_row, feat, k_w, h, in_dim);
                    mat_vec_f32(xv_row, feat, v_w, h, in_dim);
                    for i in 0..h {
                        xk_row[i] += k_b[i];
                        xv_row[i] += v_b[i];
                    }
                } else {
                    // Padded member: the feature is zero, so wk·0 + bk = bk
                    // (it still participates because attn_mask is None here).
                    xk_row.copy_from_slice(&k_b[..h]);
                    xv_row.copy_from_slice(&v_b[..h]);
                }
            }

            // 3. Single-query attention over the group's GROUP_SIZE patches,
            //    per head, scale 1/√head_dim, softmax, weighted sum of V.
            for head in 0..n_heads {
                let q_head = &xq[head * head_dim..(head + 1) * head_dim];
                for m in 0..GROUP_SIZE {
                    let k_off = m * h + head * head_dim;
                    scores[m] = dot_product(q_head, &xk[k_off..k_off + head_dim]) * scale;
                }
                softmax(&mut scores);
                let out_off = head * head_dim;
                let head_out = &mut attn_out[out_off..out_off + head_dim];
                for v in head_out.iter_mut() {
                    *v = 0.0;
                }
                for m in 0..GROUP_SIZE {
                    let v_off = m * h + head * head_dim;
                    accumulate_weighted(head_out, &xv[v_off..v_off + head_dim], scores[m]);
                }
            }

            // 4. Output projection: out = wo·attn + bo  (1152 → 1152).
            mat_vec_f32(&mut proj_in, &attn_out, o_w, h, h);
            for i in 0..h {
                proj_in[i] += o_b[i];
            }

            // 5. Projector SwiGLU: down( silu(gate(x)) * up(x) )  (1152 → 2560).
            mat_vec_f32(&mut gate, &proj_in, gate_w, inter, h);
            mat_vec_f32(&mut up, &proj_in, up_w, inter, h);
            for i in 0..inter {
                let g = gate[i];
                mid[i] = (g / (1.0 + (-g).exp())) * up[i];
            }
            mat_vec_f32(
                &mut out[gi * text_h..(gi + 1) * text_h],
                &mid,
                down_w,
                text_h,
                inter,
            );
        }

        Ok(out)
    }

    #[inline]
    fn fetch(&self, name: &str) -> Result<OwnedBytes, String> {
        self.backend
            .fetch_tensor(name)
            .map_err(|e| format!("{name}: {e}"))
    }
}

/// Integer square root (floor).
#[inline]
fn isqrt(n: usize) -> usize {
    if n == 0 {
        return 0;
    }
    let mut x = (n as f64).sqrt() as usize;
    // Correct any float rounding.
    while x * x > n {
        x -= 1;
    }
    while (x + 1) * (x + 1) <= n {
        x += 1;
    }
    x
}

#[inline]
fn bytes_to_f32(bytes: &[u8]) -> &[f32] {
    assert!(bytes.len().is_multiple_of(4));
    unsafe { std::slice::from_raw_parts(bytes.as_ptr() as *const f32, bytes.len() / 4) }
}
